import { useEffect, useState } from 'react';

export function useFeatureFlag(flagKey: string, defaultValue = false) {
  const [isEnabled, setIsEnabled] = useState(defaultValue);

  useEffect(() => {
    fetch(`/api/flags/${flagKey}`)
      .then((res) => res.json())
      .then((data) => setIsEnabled(!!data.enabled))
      .catch(() => setIsEnabled(defaultValue));
  }, [flagKey, defaultValue]);

  return isEnabled;
}

// Provider simples
const FeatureFlagsProvider = ({ children }) => {
  const [flags, setFlags] = useState({});

  useEffect(() => {
    fetch('/api/flags')
      .then(res => res.json())
      .then(setFlags);
  }, []);

  return (
    <FeatureFlagsContext.Provider value={flags}>
      {children}
    </FeatureFlagsContext.Provider>
  );
};

// Targeting por usuário
function useFeatureFlag(flagKey: string, user?: User) {
  const [isEnabled, setIsEnabled] = useState(false);

  useEffect(() => {
    if (!user) return;

    fetch(`/api/flags/${flagKey}?userId=${user.id}`)
      .then(res => res.json())
      .then(data => setIsEnabled(data.enabled));
  }, [flagKey, user]);

  return isEnabled;
}

// Rollback automático
function useFeatureFlagWithRollback(flagKey: string) {
  const [isEnabled, setIsEnabled] = useState(false);
  const [errorRate, setErrorRate] = useState(0);

  useEffect(() => {
    // Monitora taxa de erro
    const interval = setInterval(() => {
      fetch('/api/metrics/errors')
        .then(res => res.json())
        .then(data => {
          if (data.errorRate > 0.05) { // 5%
            setIsEnabled(false); // Rollback automático
          }
        });
    }, 60000);

    return () => clearInterval(interval);
  }, []);

  return isEnabled;
}
